1	<script lang="ts">
2		import type { Message, MessageFile } from "$lib/types/Message";
3		import { onDestroy } from "svelte";
4	
5		import IconOmni from "$lib/components/icons/IconOmni.svelte";
6		import CarbonCaretDown from "~icons/carbon/caret-down";
7		import CarbonDirectionRight from "~icons/carbon/direction-right-01";
8		import IconArrowUp from "~icons/lucide/arrow-up";
9		import IconMic from "~icons/lucide/mic";
10	
11		import ChatInput from "./ChatInput.svelte";
12		import VoiceRecorder from "./VoiceRecorder.svelte";
13		import StopGeneratingBtn from "../StopGeneratingBtn.svelte";
14		import type { Model } from "$lib/types/Model";
15		import FileDropzone from "./FileDropzone.svelte";
16		import RetryBtn from "../RetryBtn.svelte";
17		import file2base64 from "$lib/utils/file2base64";
18		import { base } from "$app/paths";
19		import ChatMessage from "./ChatMessage.svelte";
20		import ScrollToBottomBtn from "../ScrollToBottomBtn.svelte";
21		import ScrollToPreviousBtn from "../ScrollToPreviousBtn.svelte";
22		import { browser } from "$app/environment";
23		import { snapScrollToBottom } from "$lib/actions/snapScrollToBottom";
24		import SystemPromptModal from "../SystemPromptModal.svelte";
25		import ShareConversationModal from "../ShareConversationModal.svelte";
26		import ChatIntroduction from "./ChatIntroduction.svelte";
27		import UploadedFile from "./UploadedFile.svelte";
28		import { useSettingsStore } from "$lib/stores/settings";
29		import { error } from "$lib/stores/errors";
30		import ModelSwitch from "./ModelSwitch.svelte";
31		import { routerExamples } from "$lib/constants/routerExamples";
32		import { mcpExamples } from "$lib/constants/mcpExamples";
33		import type { RouterFollowUp, RouterExample } from "$lib/constants/routerExamples";
34		import { allBaseServersEnabled, mcpServersLoaded } from "$lib/stores/mcpServers";
35		import { shareModal } from "$lib/stores/shareModal";
36		import LucideHammer from "~icons/lucide/hammer";
37	
38		import { fly } from "svelte/transition";
39		import { cubicInOut } from "svelte/easing";
40	
41		import { isVirtualKeyboard } from "$lib/utils/isVirtualKeyboard";
42		import { requireAuthUser } from "$lib/utils/auth";
43		import { page } from "$app/state";
44		import {
45			isMessageToolCallUpdate,
46			isMessageToolErrorUpdate,
47			isMessageToolResultUpdate,
48		} from "$lib/utils/messageUpdates";
49		import type { ToolFront } from "$lib/types/Tool";
50	
51		interface Props {
52			messages?: Message[];
53			messagesAlternatives?: Message["id"][][];
54			loading?: boolean;
55			pending?: boolean;
56			shared?: boolean;
57			currentModel: Model;
58			models: Model[];
59			preprompt?: string | undefined;
60			files?: File[];
61			onmessage?: (content: string) => void;
62			onstop?: () => void;
63			onretry?: (payload: { id: Message["id"]; content?: string }) => void;
64			onshowAlternateMsg?: (payload: { id: Message["id"] }) => void;
65			draft?: string;
66		}
67	
68		let {
69			messages = [],
70			messagesAlternatives = [],
71			loading = false,
72			pending = false,
73			shared = false,
74			currentModel,
75			models,
76			preprompt = undefined,
77			files = $bindable([]),
78			draft = $bindable(""),
79			onmessage,
80			onstop,
81			onretry,
82			onshowAlternateMsg,
83		}: Props = $props();
84	
85		let isReadOnly = $derived(!models.some((model) => model.id === currentModel.id));
86	
87		let shareModalOpen = $state(false);
88		let editMsdgId: Message["id"] | null = $state(null);
89		let pastedLongContent = $state(false);
90	
91		// Voice recording state
92		let isRecording = $state(false);
93		let isTranscribing = $state(false);
94		let transcriptionEnabled = $derived(
95			!!(page.data as { transcriptionEnabled?: boolean }).transcriptionEnabled
96		);
97		let isTouchDevice = $derived(browser && navigator.maxTouchPoints > 0);
98	
99		const handleSubmit = () => {
100			if (requireAuthUser() || loading || !draft) return;
101			onmessage?.(draft);
102			draft = "";
103		};
104	
105		let lastTarget: EventTarget | null = null;
106	
107		let onDrag = $state(false);
108	
109		const onDragEnter = (e: DragEvent) => {
110			lastTarget = e.target;
111			onDrag = true;
112		};
113		const onDragLeave = (e: DragEvent) => {
114			if (e.target === lastTarget) {
115				onDrag = false;
116			}
117		};
118	
119		const onPaste = (e: ClipboardEvent) => {
120			const textContent = e.clipboardData?.getData("text");
121	
122			if (!$settings.directPaste && textContent && textContent.length >= 3984) {
123				e.preventDefault();
124				pastedLongContent = true;
125				setTimeout(() => {
126					pastedLongContent = false;
127				}, 1000);
128				const pastedFile = new File([textContent], "Pasted Content", {
129					type: "application/vnd.chatui.clipboard",
130				});
131	
132				files = [...files, pastedFile];
133			}
134	
135			if (!e.clipboardData) {
136				return;
137			}
138	
139			// paste of files
140			const pastedFiles = Array.from(e.clipboardData.files);
141			if (pastedFiles.length !== 0) {
142				e.preventDefault();
143	
144				// filter based on activeMimeTypes, including wildcards
145				const filteredFiles = pastedFiles.filter((file) => {
146					return activeMimeTypes.some((mimeType: string) => {
147						const [type, subtype] = mimeType.split("/");
148						const [fileType, fileSubtype] = file.type.split("/");
149						return (
150							(type === "*" || fileType === type) && (subtype === "*" || fileSubtype === subtype)
151						);
152					});
153				});
154	
155				files = [...files, ...filteredFiles];
156			}
157		};
158	
159		let lastMessage = $derived(browser && (messages.at(-1) as Message));
160		// Scroll signal includes tool updates and thinking blocks to trigger scroll on all content changes
161		let scrollSignal = $derived.by(() => {
162			const last = messages.at(-1) as Message | undefined;
163			if (!last) return `${messages.length}:0`;
164	
165			// Count tool updates to trigger scroll when new tools are called or complete
166			const toolUpdateCount = last.updates?.length ?? 0;
167	
168			// Include content length, tool count, and message count in signal
169			return `${last.id}:${last.content.length}:${messages.length}:${toolUpdateCount}`;
170		});
171		let streamingAssistantMessage = $derived(
172			(() => {
173				for (let i = messages.length - 1; i >= 0; i -= 1) {
174					const candidate = messages[i];
175					if (candidate.from === "assistant") {
176						return candidate;
177					}
178				}
179				return undefined;
180			})()
181		);
182		let streamingRouterMetadata = $derived(streamingAssistantMessage?.routerMetadata ?? null);
183		let streamingRouterModelName = $derived(
184			streamingRouterMetadata?.model
185				? (streamingRouterMetadata.model.split("/").pop() ?? streamingRouterMetadata.model)
186				: ""
187		);
188	
189		let lastIsError = $derived(
190			!loading &&
191				(streamingAssistantMessage?.updates?.findIndex(
192					(u) => u.type === "status" && u.status === "error"
193				) ?? -1) !== -1
194		);
195	
196		// Expose currently running tool call name (if any) from the streaming assistant message
197		const availableTools: ToolFront[] = $derived.by(
198			() => (page.data as { tools?: ToolFront[] } | undefined)?.tools ?? []
199		);
200		let streamingToolCallName = $derived.by(() => {
201			const updates = streamingAssistantMessage?.updates ?? [];
202			if (!updates.length) return null;
203			const done = new Set<string>();
204			for (const u of updates) {
205				if (isMessageToolResultUpdate(u) || isMessageToolErrorUpdate(u)) done.add(u.uuid);
206			}
207			for (let i = updates.length - 1; i >= 0; i -= 1) {
208				const u = updates[i];
209				if (isMessageToolCallUpdate(u) && !done.has(u.uuid)) {
210					return u.call.name;
211				}
212			}
213			return null;
214		});
215		let showRouterDetails = $state(false);
216		let routerDetailsTimeout: ReturnType<typeof setTimeout> | undefined;
217	
218		$effect(() => {
219			if (!currentModel.isRouter || !loading) {
220				showRouterDetails = false;
221				if (routerDetailsTimeout) {
222					clearTimeout(routerDetailsTimeout);
223					routerDetailsTimeout = undefined;
224				}
225				return;
226			}
227	
228			if (routerDetailsTimeout) {
229				clearTimeout(routerDetailsTimeout);
230			}
231	
232			showRouterDetails = false;
233			routerDetailsTimeout = setTimeout(() => {
234				showRouterDetails = true;
235			}, 500);
236		});
237	
238		let sources = $derived(
239			files?.map<Promise<MessageFile>>((file) =>
240				file2base64(file).then((value) => ({
241					type: "base64",
242					value,
243					mime: file.type,
244					name: file.name,
245				}))
246			)
247		);
248	
249		const unsubscribeShareModal = shareModal.subscribe((value) => {
250			shareModalOpen = value;
251		});
252	
253		onDestroy(() => {
254			unsubscribeShareModal();
255			shareModal.close();
256			if (routerDetailsTimeout) {
257				clearTimeout(routerDetailsTimeout);
258			}
259		});
260	
261		let chatContainer: HTMLElement | undefined = $state();
262	
263		// Force scroll to bottom when user sends a new message
264		// Pattern: user message + empty assistant message are added together
265		let prevMessageCount = $state(messages.length);
266		let forceReattach = $state(0);
267		$effect(() => {
268			if (messages.length > prevMessageCount) {
269				const last = messages.at(-1);
270				const secondLast = messages.at(-2);
271				const userJustSentMessage =
272					messages.length === prevMessageCount + 2 &&
273					secondLast?.from === "user" &&
274					last?.from === "assistant" &&
275					last?.content === "";
276	
277				if (userJustSentMessage) {
278					forceReattach++;
279				}
280			}
281			prevMessageCount = messages.length;
282		});
283	
284		// Combined scroll dependency for the action
285		let scrollDependency = $derived({ signal: scrollSignal, forceReattach });
286	
287		const settings = useSettingsStore();
288		let hideRouterExamples = $derived($settings.hidePromptExamples?.[currentModel.id] ?? false);
289	
290		// Respect per‑model multimodal toggle from settings (force enable)
291		let modelIsMultimodalOverride = $derived($settings.multimodalOverrides?.[currentModel.id]);
292		let modelIsMultimodal = $derived((modelIsMultimodalOverride ?? currentModel.multimodal) === true);
293	
294		// Determine tool support for the current model (server-provided capability with user override)
295		let modelSupportsTools = $derived(
296			($settings.toolsOverrides?.[currentModel.id] ??
297				(currentModel as unknown as { supportsTools?: boolean }).supportsTools) === true
298		);
299	
300		// Always allow common text-like files; add images only when model is multimodal
301		import { TEXT_MIME_ALLOWLIST, IMAGE_MIME_ALLOWLIST_DEFAULT } from "$lib/constants/mime";
302	
303		let activeMimeTypes = $derived(
304			Array.from(
305				new Set([
306					...TEXT_MIME_ALLOWLIST,
307					...(modelIsMultimodal
308						? (currentModel.multimodalAcceptedMimetypes ?? [...IMAGE_MIME_ALLOWLIST_DEFAULT])
309						: []),
310				])
311			)
312		);
313		let isFileUploadEnabled = $derived(activeMimeTypes.length > 0);
314		let focused = $state(false);
315	
316		let activeRouterExamplePrompt = $state<string | null>(null);
317		// Use MCP examples when all base servers are enabled, otherwise use router examples
318		let activeExamples = $derived<RouterExample[]>(
319			$allBaseServersEnabled ? mcpExamples : routerExamples
320		);
321		let routerFollowUps = $derived<RouterFollowUp[]>(
322			activeRouterExamplePrompt
323				? (activeExamples.find((ex) => ex.prompt === activeRouterExamplePrompt)?.followUps ?? [])
324				: []
325		);
326		let routerUserMessages = $derived(messages.filter((msg) => msg.from === "user"));
327		let shouldShowRouterFollowUps = $derived(
328			!draft.length &&
329				activeRouterExamplePrompt &&
330				routerFollowUps.length > 0 &&
331				routerUserMessages.length === 1 &&
332				currentModel.isRouter &&
333				!hideRouterExamples &&
334				!loading
335		);
336	
337		$effect(() => {
338			if (!currentModel.isRouter || !messages.length) {
339				activeRouterExamplePrompt = null;
340				return;
341			}
342	
343			const firstUserMessage = messages.find((msg) => msg.from === "user");
344			if (!firstUserMessage) {
345				activeRouterExamplePrompt = null;
346				return;
347			}
348	
349			const match = activeExamples.find((ex) => ex.prompt.trim() === firstUserMessage.content.trim());
350			activeRouterExamplePrompt = match ? match.prompt : null;
351		});
352	
353		function triggerPrompt(prompt: string) {
354			if (requireAuthUser() || loading) return;
355			draft = prompt;
356			handleSubmit();
357		}
358	
359		async function startExample(example: RouterExample) {
360			if (requireAuthUser()) return;
361			activeRouterExamplePrompt = example.prompt;
362	
363			if (browser && example.attachments?.length) {
364				const loadedFiles: File[] = [];
365				for (const attachment of example.attachments) {
366					try {
367						const response = await fetch(`${base}/${attachment.src}`);
368						if (!response.ok) continue;
369	
370						const blob = await response.blob();
371						const name = attachment.src.split("/").pop() ?? "attachment";
372						loadedFiles.push(
373							new File([blob], name, { type: blob.type || "application/octet-stream" })
374						);
375					} catch (err) {
376						console.error("Error loading attachment:", err);
377					}
378				}
379				files = loadedFiles;
380			}
381	
382			triggerPrompt(example.prompt);
383		}
384	
385		function startFollowUp(followUp: RouterFollowUp) {
386			triggerPrompt(followUp.prompt);
387		}
388	
389		async function handleRecordingConfirm(audioBlob: Blob) {
390			isRecording = false;
391			isTranscribing = true;
392	
393			try {
394				const response = await fetch(`${base}/api/transcribe`, {
395					method: "POST",
396					headers: { "Content-Type": audioBlob.type },
397					body: audioBlob,
398				});
399	
400				if (!response.ok) {
401					throw new Error(await response.text());
402				}
403	
404				const { text } = await response.json();
405				const trimmedText = text?.trim();
406				if (trimmedText) {
407					// Append transcribed text to draft
408					draft = draft.trim() ? `${draft.trim()} ${trimmedText}` : trimmedText;
409				}
410			} catch (err) {
411				console.error("Transcription error:", err);
412				$error = "Transcription failed. Please try again.";
413			} finally {
414				isTranscribing = false;
415			}
416		}
417	
418		async function handleRecordingSend(audioBlob: Blob) {
419			isRecording = false;
420			isTranscribing = true;
421	
422			try {
423				const response = await fetch(`${base}/api/transcribe`, {
424					method: "POST",
425					headers: { "Content-Type": audioBlob.type },
426					body: audioBlob,
427				});
428	
429				if (!response.ok) {
430					throw new Error(await response.text());
431				}
432	
433				const { text } = await response.json();
434				const trimmedText = text?.trim();
435				if (trimmedText) {
436					// Set draft and send immediately
437					draft = draft.trim() ? `${draft.trim()} ${trimmedText}` : trimmedText;
438					handleSubmit();
439				}
440			} catch (err) {
441				console.error("Transcription error:", err);
442				$error = "Transcription failed. Please try again.";
443			} finally {
444				isTranscribing = false;
445			}
446		}
447	
448		function handleRecordingError(message: string) {
449			console.error("Recording error:", message);
450			isRecording = false;
451			$error = message;
452		}
453	</script>
454	
455	<svelte:window
456		ondragenter={onDragEnter}
457		ondragleave={onDragLeave}
458		ondragover={(e) => {
459			e.preventDefault();
460		}}
461		ondrop={(e) => {
462			e.preventDefault();
463			onDrag = false;
464		}}
465	/>
466	
467	<div class="relative z-[-1] min-h-0 min-w-0">
468		{#if shareModalOpen}
469			<ShareConversationModal open={shareModalOpen} onclose={() => shareModal.close()} />
470		{/if}
471		<div
472			class="scrollbar-custom h-full overflow-y-auto"
473			use:snapScrollToBottom={scrollDependency}
474			bind:this={chatContainer}
475		>
476			<div
477				class="mx-auto flex h-full max-w-3xl flex-col gap-6 px-5 pt-6 sm:gap-8 xl:max-w-4xl xl:pt-10"
478			>
479				{#if preprompt && preprompt != currentModel.preprompt}
480					<SystemPromptModal preprompt={preprompt ?? ""} />
481				{/if}
482	
483				{#if messages.length > 0}
484					<div class="flex h-max flex-col gap-8 pb-52">
485						{#each messages as message, idx (message.id)}
486							<ChatMessage
487								{loading}
488								{message}
489								alternatives={messagesAlternatives.find((a) => a.includes(message.id)) ?? []}
490								isAuthor={!shared}
491								readOnly={isReadOnly}
492								isLast={idx === messages.length - 1}
493								bind:editMsdgId
494								onretry={(payload) => onretry?.(payload)}
495								onshowAlternateMsg={(payload) => onshowAlternateMsg?.(payload)}
496							/>
497						{/each}
498						{#if isReadOnly}
499							<ModelSwitch {models} {currentModel} />
500						{/if}
501					</div>
502				{:else if pending}
503					<ChatMessage
504						loading={true}
505						message={{
506							id: "0-0-0-0-0",
507							content: "",
508							from: "assistant",
509							children: [],
510						}}
511						isAuthor={!shared}
512						readOnly={isReadOnly}
513					/>
514				{:else}
515					<ChatIntroduction
516						{currentModel}
517						onmessage={(content) => {
518							onmessage?.(content);
519						}}
520					/>
521				{/if}
522			</div>
523	
524			<ScrollToPreviousBtn class="fixed bottom-48 right-4 lg:right-10" scrollNode={chatContainer} />
525	
526			<ScrollToBottomBtn class="fixed bottom-36 right-4 lg:right-10" scrollNode={chatContainer} />
527		</div>
528	
529		<div
530			class="pointer-events-none absolute inset-x-0 bottom-0 z-0 mx-auto flex w-full
531				max-w-3xl flex-col items-center justify-center bg-gradient-to-t from-white
532				via-white/100 to-white/0 px-3.5 pt-2 dark:border-gray-800
533				dark:from-gray-900 dark:via-gray-900/100
534				dark:to-gray-900/0 max-sm:py-0 sm:px-5 md:pb-4 xl:max-w-4xl [&>*]:pointer-events-auto"
535		>
536			{#if !draft.length && !messages.length && !sources.length && !loading && currentModel.isRouter && activeExamples.length && !hideRouterExamples && !lastIsError && $mcpServersLoaded}
537				<div
538					class="no-scrollbar mb-3 flex w-full select-none justify-start gap-2 overflow-x-auto whitespace-nowrap text-gray-400 dark:text-gray-500"
539				>
540					{#each activeExamples as ex}
541						<button
542							class="flex items-center rounded-lg bg-gray-100/90 px-2 py-0.5 text-center text-sm backdrop-blur hover:text-gray-500 dark:bg-gray-700/50 dark:hover:text-gray-400"
543							onclick={() => startExample(ex)}>{ex.title}</button
544						>
545					{/each}
546				</div>
547			{/if}
548			{#if shouldShowRouterFollowUps && !lastIsError}
549				<div
550					class="no-scrollbar mb-3 flex w-full select-none justify-start gap-2 overflow-x-auto whitespace-nowrap text-gray-400 dark:text-gray-500"
551				>
552					<!-- <span class=" text-gray-500 dark:text-gray-400">Follow ups</span> -->
553					{#each routerFollowUps as followUp}
554						<button
555							class="flex items-center gap-1 rounded-lg bg-gray-100/90 px-2 py-0.5 text-center text-sm backdrop-blur hover:text-gray-500 dark:bg-gray-700/50 dark:hover:text-gray-400"
556							onclick={() => startFollowUp(followUp)}
557						>
558							<CarbonDirectionRight class="scale-y-[-1] text-xs" />
559							{followUp.title}</button
560						>
561					{/each}
562				</div>
563			{/if}
564			{#if sources?.length && !loading}
565				<div
566					in:fly|local={sources.length === 1 ? { y: -20, easing: cubicInOut } : undefined}
567					class="flex flex-row flex-wrap justify-center gap-2.5 rounded-xl pb-3"
568				>
569					{#each sources as source, index}
570						{#await source then src}
571							<UploadedFile
572								file={src}
573								onclose={() => {
574									files = files.filter((_, i) => i !== index);
575								}}
576							/>
577						{/await}
578					{/each}
579				</div>
580			{/if}
581	
582			<div class="w-full">
583				<div class="flex w-full *:mb-3">
584					{#if !loading && lastIsError}
585						<RetryBtn
586							classNames="ml-auto"
587							onClick={() => {
588								if (lastMessage && lastMessage.ancestors) {
589									onretry?.({
590										id: lastMessage.id,
591									});
592								}
593							}}
594						/>
595					{/if}
596				</div>
597				<form
598					tabindex="-1"
599					aria-label={isFileUploadEnabled ? "file dropzone" : undefined}
600					onsubmit={(e) => {
601						e.preventDefault();
602						handleSubmit();
603					}}
604					class={{
605						"relative flex w-full max-w-4xl flex-1 items-center rounded-xl border bg-gray-100 dark:border-gray-700 dark:bg-gray-800": true,
606						"opacity-30": isReadOnly,
607						"max-sm:mb-4": focused && isVirtualKeyboard(),
608					}}
609				>
610					{#if isRecording || isTranscribing}
611						<VoiceRecorder
612							{isTranscribing}
613							{isTouchDevice}
614							oncancel={() => {
615								isRecording = false;
616							}}
617							onconfirm={handleRecordingConfirm}
618							onsend={handleRecordingSend}
619							onerror={handleRecordingError}
620						/>
621					{:else if onDrag && isFileUploadEnabled}
622						<FileDropzone bind:files bind:onDrag mimeTypes={activeMimeTypes} />
623					{:else}
624						<div
625							class="flex w-full flex-1 rounded-xl border-none bg-transparent"
626							class:paste-glow={pastedLongContent}
627						>
628							{#if lastIsError}
629								<ChatInput value="Sorry, something went wrong. Please try again." disabled={true} />
